#[test]
fn test_llm_start_payload_load_json() {
    let json = r####"
{
  "provider": "openai",
  "modelId": "gpt-4o-mini",
  "messageCount": 4,
  "attempt": 0
}
"####;
    let ctx = LoadContext::default();
    let result = LlmStartPayload::from_json(json, &ctx);
    assert!(result.is_ok(), "Failed to load from JSON: {:?}", result.err());
    let instance = result.unwrap();
    assert!(instance.provider.is_some(), "Expected provider to be Some");
    assert_eq!(instance.provider.as_ref().unwrap(), &"openai");
    assert!(instance.model_id.is_some(), "Expected model_id to be Some");
    assert_eq!(instance.model_id.as_ref().unwrap(), &"gpt-4o-mini");
    assert!(instance.message_count.is_some(), "Expected message_count to be Some");
    assert_eq!(instance.message_count.as_ref().unwrap(), &4);
    assert!(instance.attempt.is_some(), "Expected attempt to be Some");
    assert_eq!(instance.attempt.as_ref().unwrap(), &0);
}

